package service

import (
	"errors"
	"fmt"
	"strings"
	"sync"

	"refactor/types"
)

type UserOrderService struct {
	mu            sync.RWMutex
	users         map[string]*types.User
	orders        map[string]*types.Order
	notifications []types.Notification
	userCounter   int
	orderCounter  int
	emailDomain   string
	maxItems      int
	adminRoles    []string

	// interface fields for dependency injection
	notifier  Notifier
	validator Validator
	store     Store
}

// NewUserOrderService wires default implementations together.
func NewUserOrderService() *UserOrderService {
	s := &UserOrderService{
		users:         make(map[string]*types.User),
		orders:        make(map[string]*types.Order),
		notifications: make([]types.Notification, 0),
		emailDomain:   "",
		maxItems:      100,
		adminRoles:    []string{"admin", "superadmin"},
	}
	s.notifier = &serviceNotifier{s: s}
	s.validator = &serviceValidator{s: s}
	s.store = &serviceStore{s: s}
	return s
}

/*** internal validation helpers ***/
func (s *UserOrderService) validateEmail(email string) error {
	if email == "" {
		return errors.New("email is required")
	}
	if !strings.Contains(email, "@") {
		return errors.New("email must contain @")
	}
	parts := strings.Split(email, "@")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return errors.New("email format is invalid")
	}
	if !strings.Contains(parts[1], ".") {
		return errors.New("email domain must contain a dot")
	}
	if s.emailDomain != "" && parts[1] != s.emailDomain {
		return fmt.Errorf("email must be from domain %s", s.emailDomain)
	}
	return nil
}

func (s *UserOrderService) validateOrder(items []types.OrderItem) error {
	if len(items) == 0 {
		return errors.New("order must have at least one item")
	}
	if len(items) > s.maxItems {
		return fmt.Errorf("order cannot exceed %d items", s.maxItems)
	}
	for i, item := range items {
		if item.ProductID == "" {
			return fmt.Errorf("item %d: product ID is required", i)
		}
		if item.Price < 0 {
			return fmt.Errorf("item %d: price cannot be negative", i)
		}
		if item.Quantity <= 0 {
			return fmt.Errorf("item %d: quantity must be positive", i)
		}
	}
	return nil
}

/*** internal store helpers used by the Store implementation ***/
func (s *UserOrderService) createUserInternal(u *types.User) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, exists := s.users[u.ID]; exists {
		return nil, fmt.Errorf("user %s already exists", u.ID)
	}
	s.users[u.ID] = u
	return u, nil
}

func (s *UserOrderService) getUserInternal(id string) (*types.User, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	if !ok {
		return nil, fmt.Errorf("user %s not found", id)
	}
	return u, nil
}

func (s *UserOrderService) updateUserInternal(u *types.User) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	orig, ok := s.users[u.ID]
	if !ok {
		return nil, fmt.Errorf("user %s not found", u.ID)
	}
	orig.Name = u.Name
	orig.Role = u.Role
	orig.Email = u.Email
	orig.Verified = u.Verified
	return orig, nil
}

func (s *UserOrderService) deleteUserInternal(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[id]; !ok {
		return fmt.Errorf("user %s not found", id)
	}
	for _, order := range s.orders {
		if order.UserID == id && order.Status == "active" {
			return fmt.Errorf("cannot delete user %s: has active orders", id)
		}
	}
	delete(s.users, id)
	return nil
}

/*** public API methods ***/
func (s *UserOrderService) CreateUser(email, name, role string) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if err := s.validator.ValidateEmail(email); err != nil {
		return nil, err
	}
	// duplicate email check
	for _, u := range s.users {
		if u.Email == email {
			return nil, errors.New("email already registered")
		}
	}
	if role == "" {
		role = "user"
	}
	s.userCounter++
	user := &types.User{
		ID:       fmt.Sprintf("user-%d", s.userCounter),
		Email:    email,
		Name:     name,
		Role:     role,
		Verified: false,
	}
	s.users[user.ID] = user

	// welcome notification via Notifier
	subject := fmt.Sprintf("Welcome to our platform, %s!", name)
	body := fmt.Sprintf(
		"Hi %s,\n\nYour account has been created with email %s.\nPlease verify your email to get started.\n\nBest regards,\nThe Team",
		name, email,
	)
	s.notifier.Send(types.Notification{To: email, Subject: subject, Body: body})

	return user, nil
}

func (s *UserOrderService) GetUser(id string) (*types.User, error) {
	return s.store.GetUser(id)
}

func (s *UserOrderService) UpdateUser(id, name, role string) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[id]
	if !ok {
		return nil, fmt.Errorf("user %s not found", id)
	}
	if name != "" {
		u.Name = name
	}
	if role != "" {
		u.Role = role
	}
	return u, nil
}

func (s *UserOrderService) DeleteUser(id string) error {
	return s.store.DeleteUser(id)
}

func (s *UserOrderService) VerifyEmail(userID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[userID]
	if !ok {
		return fmt.Errorf("user %s not found", userID)
	}
	u.Verified = true
	return nil
}
EOF

